<script setup lang="ts">
import {computed,onMounted,ref,watch} from 'vue';import {useRoute,useRouter} from 'vue-router';import WorkflowSteps from '../../components/agent/WorkflowSteps.vue';import AgentResultMap from '../../components/agent/AgentResultMap.vue';import {agentRequest} from '../../services/agentApi';
const route=useRoute(),router=useRouter();const taskId=String(route.params.taskId);const packageId=ref(String(route.params.packageId));const task=ref<any>();const bundle=ref<any>();const overlays=ref<any>();const selectedLegId=ref('');const tab=ref<'procedure'|'424'>('procedure');const mapTab=ref<'map'|'source'>('map');const error=ref('');const showGeo=ref(false);
const pkg=computed(()=>bundle.value?.package);const result=computed(()=>bundle.value?.result);const pir=computed(()=>result.value?.pir);const selectedLeg=computed(()=>pir.value?.legs?.find((l:any)=>l.legId===selectedLegId.value));const geometryMissing=computed(()=>result.value?.geojson?.features?.filter((f:any)=>f.properties?.featureType==='LEG'&&!f.geometry).length||0);
onMounted(load);watch(()=>route.params.packageId,()=>{packageId.value=String(route.params.packageId);load()});async function load(){try{[task.value,bundle.value]=await Promise.all([agentRequest(`/tasks/${taskId}`),agentRequest(`/packages/${packageId.value}/result`)]);selectedLegId.value=pir.value?.legs?.[0]?.legId||'';if(result.value?.procedureId){try{overlays.value=await agentRequest(`/procedures/${result.value.procedureId}/overlays`)}catch{overlays.value=undefined}}}catch(e){error.value=msg(e)}}function openPackage(id:string){router.push(`/agent-tasks/${taskId}/results/${id}`)}async function retry(){await agentRequest(`/packages/${packageId.value}/retry`,{method:'POST'});router.push(`/agent-tasks/${taskId}/packages`)}function fix(id:string){return pir.value?.fixes?.find((f:any)=>f.fixId===id)?.identifier||id||'—'}function constraint(value:any){if(!value||value.type==='NONE')return'—';return value.rawText||[value.type,value.lowerFt,value.upperFt].filter(x=>x!==null&&x!==undefined).join(' ')}function download(name:string,text:string,type:string){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();URL.revokeObjectURL(a.href)}async function copy424(){await navigator.clipboard.writeText(result.value?.candidate424?.text||'')}function msg(e:unknown){return e instanceof Error?e.message:String(e)}
</script>
<template><main v-if="task&&bundle" class="page"><WorkflowSteps :current="3"/><header><div><button @click="router.push(`/agent-tasks/${taskId}/packages`)">← 返回程序包分组</button><h1>{{pkg.procedureName}}</h1><p>{{task.airportIcao}} {{task.airportName}} · {{pkg.procedureCategory}} · RWY {{pkg.runways.join(', ')||'—'}}</p></div><div><span :class="['status',pkg.status]">{{pkg.status}}</span><button @click="retry">重新识别</button><button @click="download(`${pkg.procedureName}.geojson`,JSON.stringify(result?.geojson,null,2),'application/geo+json')">导出 GeoJSON</button><button class="primary" @click="download(`${pkg.procedureName}.424.txt`,result?.candidate424?.text||'','text/plain')">导出 424</button></div></header><p v-if="error" class="error">{{error}}</p><section class="result-layout"><aside class="packages"><h3>全部程序包</h3><div v-for="category in ['SID','STAR','APPROACH']" :key="category"><b>{{category}}</b><button v-for="item in task.packages.filter((p:any)=>p.procedureCategory===category)" :key="item.packageId" :class="{active:item.packageId===pkg.packageId}" @click="openPackage(item.packageId)"><span>{{item.procedureName}}</span><em>{{item.status}}</em></button></div></aside><section class="map-area"><nav><button :class="{active:mapTab==='map'}" @click="mapTab='map'">地图</button><button :class="{active:mapTab==='source'}" :disabled="!overlays?.overlays?.length" @click="mapTab='source'">原图叠加</button><button @click="showGeo=true">GeoJSON 源码</button><span v-if="geometryMissing">{{geometryMissing}} 条 Leg 坐标不足</span></nav><AgentResultMap v-if="mapTab==='map'" :geojson="result?.geojson" :selected-leg-id="selectedLegId" @select-leg="selectedLegId=$event"/><div v-else class="overlay-scroll"><img v-for="name in overlays?.overlays||[]" :key="name" :src="`/api/agent/procedures/${result.procedureId}/files/${name}`" :alt="name"></div><div class="legend"><span><i class="exact"></i>精确/明确坐标</span><span><i class="derived"></i>推导几何</span><span><i class="display"></i>显示几何</span><span><i class="missing"></i>未生成几何</span></div></section><aside class="details"><nav><button :class="{active:tab==='procedure'}" @click="tab='procedure'">程序信息</button><button :class="{active:tab==='424'}" @click="tab='424'">ARINC 424</button></nav><section v-if="tab==='procedure'"><div class="summary"><p><span>Route</span>{{pir?.routes?.length||0}}</p><p><span>Leg</span>{{pir?.legs?.length||0}}</p><p><span>Fix</span>{{pir?.fixes?.length||0}}</p></div><div class="legs"><button v-for="leg in pir?.legs" :key="leg.legId" :class="{active:leg.legId===selectedLegId}" @click="selectedLegId=leg.legId"><b>{{leg.sequence}} · {{leg.pathTerminator}}</b><span>{{fix(leg.fromFixId)}} → {{fix(leg.toFixId)}}</span><em>{{leg.course??'—'}}° · {{leg.distanceNm??'—'}} NM</em></button></div><div v-if="selectedLeg" class="leg-detail"><h3>Leg {{selectedLeg.sequence}}</h3><dl><dt>Path Terminator</dt><dd>{{selectedLeg.pathTerminator}}</dd><dt>From / To</dt><dd>{{fix(selectedLeg.fromFixId)}} → {{fix(selectedLeg.toFixId)}}</dd><dt>Course / Distance</dt><dd>{{selectedLeg.course??'—'}}° / {{selectedLeg.distanceNm??'—'}} NM</dd><dt>Altitude</dt><dd>{{constraint(selectedLeg.altitudeConstraint)}}</dd><dt>Speed</dt><dd>{{selectedLeg.speedConstraint?.valueKias||'—'}}</dd><dt>Turn</dt><dd>{{selectedLeg.turnDirection||'—'}}</dd><dt>识别状态</dt><dd>{{selectedLeg.confidence}}</dd></dl></div></section><section v-else class="candidate"><div><span :class="['status',result?.candidate424?.status]">{{result?.candidate424?.status}}</span><button @click="copy424">复制</button><button @click="download(`${pkg.procedureName}.424.txt`,result?.candidate424?.text||'','text/plain')">下载</button></div><pre>{{result?.candidate424?.text||'尚未生成 424 Candidate'}}</pre><h3>完整性</h3><p v-if="!result?.candidate424?.missingFields?.length">已通过固定宽度生成与回读检查。</p><ul v-else><li v-for="field in result.candidate424.missingFields" :key="field">{{field}}</li></ul><button class="compare" @click="router.push(`/agent-tasks/${taskId}/packages`)">与 Jeppesen 424 对比（在程序包工作台运行）</button></section></aside></section><div v-if="showGeo" class="modal" @click.self="showGeo=false"><article><header><h2>GeoJSON 源码</h2><button @click="showGeo=false">关闭</button></header><pre>{{JSON.stringify(result?.geojson,null,2)}}</pre></article></div></main></template>
<style scoped>.page{padding:24px;color:#102a43}.page>header{display:flex;justify-content:space-between;align-items:end;margin:24px 0}.page>header h1{margin:8px 0}.page>header p{color:#627d98}.page>header button{border:1px solid #c8d2df;background:#fff;padding:9px 12px;border-radius:7px;margin-left:6px}.page>header>div:first-child button{border:0;padding-left:0;color:#52606d}.primary{background:#1769e0!important;color:#fff!important}.status{display:inline-block;padding:6px 9px;border-radius:6px;background:#e7f5ed;color:#237a4b;font-size:12px}.status.FAILED,.status.REQUIRES_REVIEW,.status.\34 24_INCOMPLETE{background:#feeceb;color:#b42318}.result-layout{display:grid;grid-template-columns:230px minmax(520px,1fr) 390px;height:calc(100vh - 210px);min-height:650px;background:#fff;border-radius:14px;overflow:hidden}.packages{background:#f5f8fb;padding:18px;overflow:auto}.packages h3{margin-top:0}.packages>div>b{display:block;font-size:11px;color:#829ab1;margin:20px 5px 6px}.packages button{display:block;width:100%;border:0;background:none;text-align:left;padding:10px;border-radius:7px}.packages button.active{background:#dfeafa}.packages span,.packages em{display:block}.packages em{font-size:10px;color:#627d98;font-style:normal;margin-top:4px}.map-area{position:relative;display:flex;flex-direction:column}.map-area>nav{height:46px;display:flex;align-items:center;padding:0 12px;border-bottom:1px solid #e4eaf0}.map-area nav button,.details>nav button{border:0;background:none;padding:8px 12px;color:#52606d}.map-area nav button.active,.details>nav button.active{color:#174ea6;font-weight:700;border-bottom:2px solid #1769e0}.map-area nav span{margin-left:auto;color:#b45309;font-size:12px}.map-area :deep(.map){flex:1}.overlay-scroll{flex:1;overflow:auto;padding:10px}.overlay-scroll img{width:100%;border:1px solid #dbe4ee;border-radius:7px;margin-bottom:8px}.legend{position:absolute;left:15px;bottom:15px;background:#fff;padding:9px;border-radius:7px;box-shadow:0 2px 12px #102a4322;display:flex;gap:10px;font-size:11px}.legend i{display:inline-block;width:20px;border-top:3px solid;margin-right:4px}.legend .exact{border-color:#1769e0}.legend .derived{border-color:#00a67d}.legend .display{border-color:#d97706;border-top-style:dashed}.legend .missing{border-color:#94a3b8}.details{border-left:1px solid #e4eaf0;overflow:auto}.details>nav{position:sticky;top:0;background:#fff;border-bottom:1px solid #e4eaf0;padding:7px;z-index:2}.details>section{padding:16px}.summary{display:flex;gap:10px}.summary p{flex:1;background:#f4f7fa;padding:9px;margin:0}.summary span{display:block;color:#829ab1;font-size:10px}.legs{margin-top:14px}.legs button{display:grid;grid-template-columns:70px 1fr auto;width:100%;border:0;border-bottom:1px solid #edf1f5;background:#fff;padding:10px;text-align:left}.legs button.active{background:#eaf2fd}.legs span,.legs em{font-style:normal;color:#52606d}.leg-detail{background:#f5f8fb;padding:12px;margin-top:12px}.leg-detail dl{display:grid;grid-template-columns:1fr 1.3fr;gap:8px}.leg-detail dt{color:#627d98}.leg-detail dd{margin:0}.candidate>div{display:flex;align-items:center;gap:8px}.candidate>div button,.compare{border:1px solid #c8d2df;background:#fff;padding:7px;border-radius:6px}.candidate pre,.modal pre{white-space:pre-wrap;word-break:break-all;background:#10233e;color:#dcecff;padding:12px;max-height:430px;overflow:auto}.compare{width:100%;margin-top:15px}.modal{position:fixed;inset:0;background:#102a4366;display:grid;place-items:center;z-index:100}.modal article{background:#fff;width:min(900px,90vw);max-height:85vh;padding:18px;border-radius:12px}.modal header{display:flex;justify-content:space-between}.modal pre{max-height:68vh}.error{background:#fee2e2;color:#991b1b;padding:12px}@media(max-width:1100px){.result-layout{grid-template-columns:190px 1fr;height:auto}.details{grid-column:1/-1;max-height:none}.map-area{min-height:600px}}</style>
